        self.value: Any = value
        self.prev: Optional["_Node"] = None
        self.next: Optional["_Node"] = None


class LRUCache:
    def __init__(self, capacity: int) -> None:
        if capacity <= 0:
            raise ValueError("capacity must be positive")
        self._capacity: int = capacity
        self._cache: dict[int, _Node] = {}
        self._lock: threading.Lock = threading.Lock()
        self._head: _Node = _Node()
        self._tail: _Node = _Node()
        self._head.next = self._tail
        self._tail.prev = self._head

    def _add_to_head(self, node: _Node) -> None:
        node.prev = self._head
        node.next = self._head.next
        if self._head.next:
            self._head.next.prev = node
        self._head.next = node

    def _remove_node(self, node: _Node) -> None:
        if node.prev:
            node.prev.next = node.next
        if node.next:
            node.next.prev = node.prev

    def _move_to_head(self, node: _Node) -> None:
        self._remove_node(node)
        self._add_to_head(node)

    def _remove_tail(self) -> _Node:
        node = self._tail.prev
        if node is None:
            raise RuntimeError("cannot remove from empty cache")
        self._remove_node(node)
        return node

    def get(self, key: int) -> Any:
        with self._lock:
            node = self._cache.get(key)
            if node is None:
                return -1
            self._move_to_head(node)
            return node.value

    def put(self, key: int, value: Any) -> None:
        with self._lock:
            node = self._cache.get(key)
            if node is not None:
                node.value = value
                self._move_to_head(node)
            else:
                new_node = _Node(key, value)
                self._cache[key] = new_node
                self._add_to_head(new_node)
                if len(self._cache) > self._capacity:
                    tail_node = self._remove_tail()
                    del self._cache[tail_node.key]

    def size(self) -> int:
        with self._lock:
            return len(self._cache)
